from flask import Flask, request, jsonify, g, session
from werkzeug.security import check_password_hash, generate_password_hash
import sqlite3
from itsdangerous import URLSafeTimedSerializer as uts

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your secret key'

# database connection settings
DATABASE = 'users.db'
user_db = sqlite3.connect(DATABASE)

def create_tables():
    user_db.execute('''CREATE TABLE IF NOT EXISTS users
                     (email text PRIMARY KEY, password text)''')

    user_db.execute('''CREATE TABLE IF NOT EXISTS sessions
                     (session_id text PRIMARY KEY, email text,
                      last_seen real, two_factor_enabled integer)''')
    user_db.commit()

def get_db():
    return user_db

@app.before_request
def load_session_data():
    if 'session_id' in session:
        g.session = get_db().execute('SELECT * FROM sessions WHERE session_id=?',
                                    (session['session_id'],)).fetchone()
    else:
        g.session = None

@app.route('/update', methods=['POST'])
def update_profile():
    data = request.form
    email = data.get('email')
    password = data.get('password')
    two_factor_enabled = int(data.get('two_factor_enabled'))

    if not g.session or g.session['email'] != email:
        return jsonify({'error': 'Unauthorized'}), 401

    if password:
        hashed_password = generate_password_hash(password)
        get_db().execute("UPDATE users SET password=? WHERE email=?",
                        (hashed_password, email))
    else:
        pass # nothing to update in this case

    if two_factor_enabled != g.session['two_factor_enabled']:
        get_db().execute('UPDATE sessions SET two_factor_enabled=?',
                        (two_factor_enabled,))
    else:
        pass # nothing to update in this case
    user_db.commit()
    return jsonify({'success': 'Profile updated'}), 200

if __name__ == '__main__':
    create_tables()
    app.run(debug=True)